import React from 'react';
import { MemoryRouter, Routes, Route } from 'react-router-dom';
import { createPlugin } from '@naap/plugin-sdk';
import { ExpenseListPage } from './pages/ExpenseList';
import { NewExpensePage } from './pages/NewExpense';
import { ReceiptsPage } from './pages/Receipts';
import { VendorsPage } from './pages/Vendors';
import { BankConnectionPage } from './pages/BankConnection';
import { BankReviewPage } from './pages/BankReview';
import { MileagePage } from './pages/Mileage';
import { BudgetsPage } from './pages/Budgets';
import { PerDiemPage } from './pages/PerDiem';
import { BillsPage } from './pages/Bills';
import './globals.css';

// Map URL path to internal route
function getInitialRoute(): string {
  const path = window.location.pathname;
  // More specific bank sub-paths first — /bank/review must beat /bank.
  if (path.includes('/bank/review')) return '/bank/review';
  if (path.includes('/bank')) return '/bank';
  if (path.includes('/receipts')) return '/receipts';
  if (path.includes('/vendors')) return '/vendors';
  if (path.includes('/mileage')) return '/mileage';
  if (path.includes('/per-diem')) return '/per-diem';
  if (path.includes('/budgets')) return '/budgets';
  if (path.includes('/bills')) return '/bills';
  if (path.includes('/new')) return '/new';
  return '/';
}

const AgentbookExpenseApp: React.FC = () => (
  <MemoryRouter initialEntries={[getInitialRoute()]}>
    <Routes>
      <Route path="/" element={<ExpenseListPage />} />
      <Route path="/new" element={<NewExpensePage />} />
      <Route path="/receipts" element={<ReceiptsPage />} />
      <Route path="/vendors" element={<VendorsPage />} />
      <Route path="/bank" element={<BankConnectionPage />} />
      <Route path="/bank/review" element={<BankReviewPage />} />
      <Route path="/mileage" element={<MileagePage />} />
      <Route path="/per-diem" element={<PerDiemPage />} />
      <Route path="/budgets" element={<BudgetsPage />} />
      <Route path="/bills" element={<BillsPage />} />
      <Route path="/*" element={<ExpenseListPage />} />
    </Routes>
  </MemoryRouter>
);

const plugin = createPlugin({
  name: 'agentbook-expense',
  version: '1.0.0',
  routes: [
    '/agentbook/expenses',
    '/agentbook/expenses/*',
    '/agentbook/receipts',
    '/agentbook/receipts/*',
    '/agentbook/vendors',
    '/agentbook/vendors/*',
    '/agentbook/bank',
    '/agentbook/bank/*',
    '/agentbook/mileage',
    '/agentbook/mileage/*',
    '/agentbook/budgets',
    '/agentbook/budgets/*',
    '/agentbook/per-diem',
    '/agentbook/per-diem/*',
    '/agentbook/bills',
    '/agentbook/bills/*',
  ],
  App: AgentbookExpenseApp,
});

export const manifest = plugin;
export const mount = plugin.mount;
export default plugin;
